   210→                    >
   211→                      {col}
   212→                    </th>
   213→                  )
   214→                )}
   215→              </tr>
   216→            </thead>
   217→            <tbody>
   218→              {releases.map((release) => (
   219→                <tr
   220→                  key={release.id}
