   224→                    opacity: release.excluded ? 0.45 : 1,
   225→                  }}
   226→                >
   227→                  {/* Project */}
   228→                  <td className="px-4 py-3">
   229→                    {release.project_id ? (
   230→                      <Link
   231→                        href={`/projects/${release.project_id}`}
   232→                        className="hover:underline"
   233→                        style={{
   234→                          fontFamily: "var(--font-dm-sans)",
   235→                          fontSize: "13px",
   236→                          color: "#111113",
   237→                          fontWeight: 500,
   238→                        }}
   239→                      >
   240→                        {release.project_name ?? "\u2014"}
   241→                      </Link>
   242→                    ) : (
   243→                      <span
   244→                        style={{
   245→                          fontFamily: "var(--font-dm-sans)",
   246→                          fontSize: "13px",
   247→                          color: "#9ca3af",
   248→                        }}
   249→                      >
   250→                        {"\u2014"}
   251→                      </span>
   252→                    )}
   253→                  </td>
   254→
   255→                  {/* Provider */}
   256→                  <td className="px-4 py-3">
   257→                    {release.provider ? (
   258→                      <ProviderBadge provider={release.provider} />
