   499→export default function ProjectsPage() {
   500→  const [createOpen, setCreateOpen] = useState(false);
   501→  const [viewMode, setViewMode] = useState<"cards" | "compact">("cards");
   502→  const [search, setSearch] = useState("");
   503→  const [sortBy, setSortBy] = useState<"updated" | "added" | "name">("updated");
   504→  const [page, setPage] = useState(1);
   505→  const { data, isLoading } = useSWR("projects", () => projectsApi.list(1, 100));
   506→  const items = data?.data ?? [];
   507→
   508→  const PAGE_SIZE = 12;
   509→  const filtered = search
   510→    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
   511→    : items;
   512→  const sorted = useMemo(() => {
   513→    const arr = [...filtered];
   514→    switch (sortBy) {
   515→      case "updated":
   516→        return arr.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
   517→      case "added":
   518→        return arr.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
   519→      case "name":
   520→        return arr.sort((a, b) => a.name.localeCompare(b.name));
   521→    }
   522→  }, [filtered, sortBy]);
   523→  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
   524→  const currentPage = Math.min(page, totalPages);
   525→  const paged = sorted.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);
   526→
