     1→"use client";
     2→
     3→import React, { useState, useMemo, useRef, useEffect, useCallback } from "react";
     4→import useSWR, { mutate } from "swr";
     5→import Link from "next/link";
     6→import { useRouter } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  releases as releasesApi,
    10→  sources as sourcesApi,
    11→  semanticReleases as srApi,
    12→} from "@/lib/api/client";
    13→import { getProviderIcon } from "@/components/ui/provider-badge";
    14→import { ProjectLogo } from "@/components/ui/project-logo";
    15→import { timeAgo } from "@/lib/format";
    16→import { Plus, ArrowRight, LayoutGrid, List, Search, Pencil, ArrowUpDown } from "lucide-react";
    17→import { SourceForm } from "@/components/sources/source-form";
    18→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    19→import { ProjectForm } from "@/components/projects/project-form";
    20→import type { Project, Source } from "@/lib/api/types";
    21→
    22→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    23→  critical: { bg: "#dc2626", text: "#ffffff" },
    24→  high: { bg: "#f97316", text: "#ffffff" },
    25→  medium: { bg: "#f59e0b", text: "#ffffff" },
    26→  low: { bg: "#6b7280", text: "#ffffff" },
    27→};
    28→
    29→/* ---------- Project Card Logo ---------- */
    30→
    31→function ProjectCardLogo({ projectId, name }: { projectId: string; name: string }) {
    32→  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
    33→    sourcesApi.listByProject(projectId)
    34→  );
    35→  return <ProjectLogo name={name} sources={data?.data} size={40} />;
    36→}
    37→
    38→/* ---------- Overflow Flow ---------- */
    39→
    40→const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
    41→const MAX_LINES = 2;
    42→const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
    43→
    44→function FlowSection({
    45→  label,
    46→  moreHref,
    47→  children,
    48→}: {
    49→  label: string;
    50→  moreHref: string;
    51→  children: React.ReactNode;
    52→}) {
    53→  const measureRef = useRef<HTMLDivElement>(null);
    54→  const moreRef = useRef<HTMLSpanElement>(null);
    55→  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    56→
    57→  const items = React.Children.toArray(children);
    58→
    59→  const measure = useCallback(() => {
    60→    const el = measureRef.current;
    61→    if (!el) return;
    62→    const nodes = el.children;
    63→    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "more…" span (last)
    64→    // Check if everything fits without overflow
    65→    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    66→      setVisibleCount(items.length);
    67→      return;
    68→    }
    69→    // Measure actual "more…" link width
    70→    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    71→    const containerWidth = el.offsetWidth;
    72→    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    73→    let lastFitting = 0;
    74→    for (let i = 1; i <= itemNodeCount; i++) {
    75→      const node = nodes[i] as HTMLElement;
    76→      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    77→      lastFitting = i;
    78→    }
    79→    // Second pass: walk backward from lastFitting until "more…" fits after the item
    80→    let count = lastFitting;
    81→    while (count > 1) {
    82→      const node = nodes[count] as HTMLElement;
    83→      const nodeBottom = node.offsetTop + node.offsetHeight;
    84→      // If this item is on line 1, "more…" can always wrap to line 2 — we're fine
    85→      if (nodeBottom <= LINE_HEIGHT) break;
    86→      // Item is on line 2 — check if "more…" fits after it on the same line
    87→      const nodeRight = node.offsetLeft + node.offsetWidth;
    88→      if (nodeRight + moreWidth <= containerWidth) break;
    89→      count--;
    90→    }
    91→    setVisibleCount(Math.max(1, count));
    92→  }, [items.length]);
    93→
    94→  useEffect(() => {
    95→    const raf = requestAnimationFrame(measure);
    96→    const obs = new ResizeObserver(measure);
    97→    if (measureRef.current) obs.observe(measureRef.current);
    98→    return () => {
    99→      cancelAnimationFrame(raf);
   100→      obs.disconnect();
   101→    };
   102→  }, [measure, items.length]);
   103→
   104→  const hasOverflow = visibleCount !== null && visibleCount < items.length;
   105→  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   106→
   107→  return (
   108→    <div className="relative">
   109→      {/* Hidden measurer — renders all items to find cutoff */}
   110→      <div
   111→        ref={measureRef}
   112→        className="text-[13px] leading-7"
   113→        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   114→        aria-hidden="true"
   115→      >
   116→        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   117→          {label}:
   118→        </span>
   119→        {items}
   120→        {/* Hidden "more…" to measure its actual width */}
   121→        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
   122→          more…
   123→        </span>
   124→      </div>
   125→      {/* Visible section */}
   126→      <div className="text-[13px] leading-7">
   127→        <span
   128→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
   129→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   130→        >
   131→          {label}:
   132→        </span>
   133→        {displayed}
   134→        {hasOverflow && (
   135→          <Link
   136→            href={moreHref}
   137→            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
   138→            style={{ color: "#e8601a" }}
   139→          >
   140→            more…
   141→          </Link>
   142→        )}
   143→      </div>
   144→    </div>
   145→  );
   146→}
   147→
   148→/* ---------- Flow Card ---------- */
   149→
   150→function ProjectFlowCard({ project }: { project: Project }) {
   151→  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
   152→  const [editingSource, setEditingSource] = useState<Source | null>(null);
   153→
   154→  const { data: srcData, mutate: mutateSources } = useSWR(
   155→    `project-${project.id}-card-sources`,
   156→    () => sourcesApi.listByProject(project.id),
   157→  );
   158→  const { data: relData } = useSWR(
   159→    `project-${project.id}-card-releases`,
   160→    () => releasesApi.listByProject(project.id, 1, 25, true),
   161→  );
   162→  const { data: srData } = useSWR(
   163→    `project-${project.id}-card-sr`,
   164→    () => srApi.list(project.id, 1, 10),
   165→  );
   166→
   167→  const sources = srcData?.data ?? [];
   168→  const releases = relData?.data ?? [];
   169→  const srItems = srData?.data ?? [];
   170→
   171→  const sourceMap = useMemo(() => {
   172→    const m = new Map<string, Source>();
   173→    for (const s of sources) m.set(s.id, s);
   174→    return m;
   175→  }, [sources]);
   176→
   177→  return (
   178→    <div
   179→      className="rounded-md px-5 py-4"
   180→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
   181→    >
   182→      {/* Header */}
   183→      <div className="flex items-center justify-between mb-2">
   184→        <div className="flex items-center gap-3 min-w-0">
   185→          <ProjectCardLogo projectId={project.id} name={project.name} />
   186→          <div className="min-w-0">
   187→            <Link
   188→              href={`/projects/${project.id}`}
   189→              className="group inline-flex items-center gap-1.5 text-[16px] font-bold transition-colors"
   190→              style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a" }}
   191→            >
   192→              {project.name}
   193→              <ArrowRight className="h-3.5 w-3.5 opacity-0 -translate-x-1 transition-all group-hover:opacity-100 group-hover:translate-x-0" />
   194→            </Link>
   195→            {project.description && (
   196→              <p
   197→                className="text-[13px] truncate"
   198→                style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
   199→              >
   200→                {project.description}
   201→              </p>
   202→            )}
   203→          </div>
   204→        </div>
   205→      </div>
   206→
   207→      {/* Sources chips */}
   208→      <div className="flex flex-wrap items-center gap-1.5 mb-3">
   209→        <span
   210→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-0.5"
   211→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   212→        >
   213→          Sources:
   214→        </span>
   215→        {sources.map((source) => (
   216→          <button
   217→            key={source.id}
   218→            onClick={() => setEditingSource(source)}
   219→            className="group/chip inline-flex items-center gap-1.5 rounded px-2 py-0.5 text-[12px] transition-colors hover:bg-[#f0f0ee]"
   220→            style={{
   221→              backgroundColor: "#fafaf9",
   222→              border: "1px solid #e8e8e5",
   223→            }}
   224→          >
   225→            <span
   226→              className="inline-block h-1.5 w-1.5 rounded-full shrink-0"
   227→              style={{ backgroundColor: source.enabled ? "#16a34a" : "#d1d5db" }}
   228→            />
   229→            {(() => { const Icon = getProviderIcon(source.provider); return Icon ? <Icon size={12} className="shrink-0" style={{ color: "#9ca3af" }} /> : null; })()}
   230→            <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}>
   231→              {source.repository}
   232→            </span>
   233→            {source.last_polled_at && (
   234→              <span style={{ color: "#9ca3af" }}>
   235→                {timeAgo(source.last_polled_at).replace(" ago", "")}
   236→              </span>
   237→            )}
   238→            <Pencil className="h-2.5 w-2.5 hidden group-hover/chip:inline shrink-0" style={{ color: "#9ca3af", opacity: 0.5 }} />
   239→          </button>
   240→        ))}
   241→        <button
   242→          onClick={() => setSourceCreateOpen(true)}
   243→          className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] font-medium rounded border transition-colors hover:bg-[#f3f3f1]"
   244→          style={{
   245→            borderColor: "#e8e8e5",
   246→            color: "#9ca3af",
   247→            fontFamily: "var(--font-dm-sans)",
   248→          }}
   249→        >
   250→          <Plus className="h-3 w-3" />
   251→          Add Source
   252→        </button>
   253→      </div>
   254→
   255→      {/* Releases flow */}
   256→      {releases.length > 0 && (
   257→        <FlowSection label="Releases" moreHref={`/releases?project=${project.id}`}>
   258→          {releases.map((r) => {
   259→            const src = sourceMap.get(r.source_id);
   260→            return (
   261→              <span key={r.id} className="inline-flex items-baseline mr-2.5">
   262→                <Link
   263→                  href={`/releases/${r.id}`}
   264→                  className={r.excluded ? "" : "text-[#2563eb] hover:underline"}
   265→                  style={{
   266→                    fontFamily: "'JetBrains Mono', monospace",
   267→                    fontSize: "12px",
   268→                    ...(r.excluded ? { color: "#c4c4c0" } : {}),
   269→                  }}
   270→                >
   271→                  {r.version}
   272→                </Link>
   273→                {src && (
   274→                  <span
   275→                    className="text-[11px] ml-1 hidden sm:inline"
   276→                    style={{ color: r.excluded ? "#dcdcda" : "#9ca3af" }}
   277→                  >
   278→                    ({src.repository.split("/").pop()})
   279→                  </span>
   280→                )}
   281→                <span
   282→                  className="text-[11px] ml-1"
   283→                  style={{ color: r.excluded ? "#dcdcda" : "#c4c4c0" }}
   284→                >
   285→                  {timeAgo(r.released_at || r.created_at).replace(" ago", "")}
   286→                </span>
   287→              </span>
   288→            );
   289→          })}
   290→        </FlowSection>
   291→      )}
   292→
   293→      {/* Semantic releases */}
   294→      {srItems.length > 0 && (
   295→        <FlowSection label="Semantic Releases" moreHref={`/semantic-releases?project=${project.id}`}>
   296→          {srItems.map((sr) => {
