   236→        {item.full_name}
   237→        <Check className="h-3 w-3" />
   238→      </span>
   239→    );
   240→  }
   241→
   242→  return (
   243→    <button
   244→      onClick={() => onTrack(item)}
   245→      disabled={tracking}
   246→      className="inline-flex flex-shrink-0 items-center gap-1.5 rounded-full px-3 py-1.5 transition-all hover:shadow-sm disabled:opacity-70"
   247→      style={{
   248→        fontFamily: "var(--font-dm-sans)",
   249→        fontSize: "12px",
   250→        color: "#111113",
   251→        backgroundColor: "#fafaf9",
   252→        border: "1px solid #e8e8e5",
   253→        whiteSpace: "nowrap",
   254→        cursor: tracking ? "wait" : "pointer",
   255→      }}
   256→    >
   257→      <ProviderIcon className="h-3 w-3" style={{ color: "#6b7280" }} />
   258→      <span>{item.full_name}</span>
   259→      <Star className="h-3 w-3" style={{ color: "#e8601a" }} />
   260→      <span style={{ color: "#6b7280", fontSize: "11px" }}>
   261→        {formatStars(item.stars)}
   262→      </span>
   263→      {tracking ? (
   264→        <Loader2
   265→          className="h-3 w-3 animate-spin"
   266→          style={{ color: "#e8601a" }}
   267→        />
   268→      ) : (
   269→        <Plus className="h-3 w-3" style={{ color: "#e8601a" }} />
   270→      )}
   271→    </button>
   272→  );
   273→}
