    38→/* ---------- Overflow Flow ---------- */
    39→
    40→const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
    41→const MAX_LINES = 2;
    42→const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
    43→
    44→function FlowSection({
    45→  label,
    46→  moreHref,
    47→  children,
    48→}: {
    49→  label: string;
    50→  moreHref: string;
    51→  children: React.ReactNode;
    52→}) {
    53→  const measureRef = useRef<HTMLDivElement>(null);
    54→  const moreRef = useRef<HTMLSpanElement>(null);
    55→  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    56→
    57→  const items = React.Children.toArray(children);
    58→
    59→  const measure = useCallback(() => {
    60→    const el = measureRef.current;
    61→    if (!el) return;
    62→    const nodes = el.children;
    63→    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "more…" span (last)
    64→
    65→    // Guard: if container has no width yet, fonts haven't loaded / layout not ready
    66→    if (el.offsetWidth === 0 || itemNodeCount <= 0) return;
    67→
    68→    // Check if everything fits without overflow
    69→    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    70→      setVisibleCount(items.length);
    71→      return;
    72→    }
    73→    // Measure actual "more…" link width
    74→    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    75→    const containerWidth = el.offsetWidth;
    76→    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    77→    let lastFitting = 0;
    78→    for (let i = 1; i <= itemNodeCount; i++) {
    79→      const node = nodes[i] as HTMLElement;
    80→      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    81→      lastFitting = i;
    82→    }
    83→    // Second pass: walk backward from lastFitting until "more…" fits after the item
    84→    let count = lastFitting;
    85→    while (count > 1) {
    86→      const node = nodes[count] as HTMLElement;
    87→      const nodeBottom = node.offsetTop + node.offsetHeight;
    88→      // If this item is on line 1, "more…" can always wrap to line 2 — we're fine
    89→      if (nodeBottom <= LINE_HEIGHT) break;
    90→      // Item is on line 2 — check if "more…" fits after it on the same line
    91→      const nodeRight = node.offsetLeft + node.offsetWidth;
    92→      if (nodeRight + moreWidth <= containerWidth) break;
    93→      count--;
    94→    }
    95→    setVisibleCount(Math.max(1, count));
    96→  }, [items.length]);
    97→
    98→  useEffect(() => {
    99→    // Schedule multiple measurement passes to handle font loading and async layout.
   100→    // A single rAF often fires before custom fonts (JetBrains Mono) have loaded,
   101→    // causing scrollHeight to be incorrect. Double-rAF + a delayed fallback
   102→    // ensures we catch the final layout.
   103→    let cancelled = false;
   104→    const raf1 = requestAnimationFrame(() => {
   105→      if (!cancelled) measure();
   106→      requestAnimationFrame(() => { if (!cancelled) measure(); });
   107→    });
   108→    const timeout = setTimeout(() => { if (!cancelled) measure(); }, 200);
   109→    const obs = new ResizeObserver(() => { if (!cancelled) measure(); });
   110→    if (measureRef.current) obs.observe(measureRef.current);
   111→    return () => {
   112→      cancelled = true;
   113→      cancelAnimationFrame(raf1);
   114→      clearTimeout(timeout);
   115→      obs.disconnect();
   116→    };
   117→  }, [measure, items.length]);
   118→
   119→  const hasOverflow = visibleCount !== null && visibleCount < items.length;
   120→  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   121→
   122→  return (
   123→    <div className="relative">
   124→      {/* Hidden measurer — renders all items to find cutoff */}
   125→      <div
   126→        ref={measureRef}
   127→        className="text-[13px] leading-7"
   128→        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   129→        aria-hidden="true"
   130→      >
   131→        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   132→          {label}:
   133→        </span>
   134→        {items}
   135→        {/* Hidden "more…" to measure its actual width */}
   136→        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
   137→          more…
   138→        </span>
   139→      </div>
   140→      {/* Visible section */}
   141→      <div className="text-[13px] leading-7">
   142→        <span
   143→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
   144→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   145→        >
   146→          {label}:
   147→        </span>
   148→        {displayed}
   149→        {hasOverflow && (
   150→          <Link
   151→            href={moreHref}
   152→            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
   153→            style={{ color: "#e8601a" }}
   154→          >
   155→            more…
   156→          </Link>
   157→        )}
   158→      </div>
   159→    </div>
   160→  );
   161→}
