   641→                style={{
   642→                  fontFamily: "var(--font-dm-sans), sans-serif",
   643→                  backgroundColor: "#fafaf9",
   644→                  borderColor: "#e8e8e5",
   645→                  color: "#111113",
   646→                }}
   647→              />
   648→              <div className="mt-3 flex justify-end">
   649→                <button
   650→                  onClick={handleSaveAgentConfig}
   651→                  disabled={saving || (promptDraft === null && rulesDraft === null)}
   652→                  className="rounded-md px-4 py-1.5 text-[13px] font-medium text-white transition-colors disabled:opacity-40"
   653→                  style={{ backgroundColor: "#e8601a" }}
