   704→                    className="w-full rounded-md border px-3 py-1.5 text-[13px] focus:outline-none focus:ring-1 disabled:opacity-50"
   705→                    style={{
   706→                      fontFamily: "'JetBrains Mono', monospace",
   707→                      backgroundColor: "#fafaf9",
   708→                      borderColor: "#e8e8e5",
   709→                      color: testVersion ? "#111113" : "#9ca3af",
   710→                    }}
   711→                  >
