   737→              {runsData?.data && runsData.data.length > 0 ? (
   738→                <div className="overflow-hidden rounded-md border" style={{ borderColor: "#e8e8e5" }}>
   739→                  <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans), sans-serif" }}>
   740→                    <thead>
   741→                      <tr style={{ backgroundColor: "#fafaf9" }}>
   742→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Trigger</th>
   743→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Status</th>
   744→                        <th className="px-4 py-2 text-left text-[11px] font-medium uppercase tracking-[0.08em]" style={{ color: "#9ca3af" }}>Started</th>
