   849→        </DialogContent>
   850→      </Dialog>
   851→
   852→      {/* Context source delete dialog */}
   853→      <ConfirmDialog
   854→        open={!!deletingCtxId}
   855→        onOpenChange={(open) => { if (!open) setDeletingCtxId(null); }}
   856→        title="Delete Context Source"
