   858→        onConfirm={async () => { if (deletingCtxId) { await ctxApi.delete(deletingCtxId); mutateCtx(); } }}
   859→      />
   860→
   861→      {/* Project delete dialog */}
   862→      <ConfirmDialog
   863→        open={deletingProject}
   864→        onOpenChange={setDeletingProject}
   865→        title="Delete Project"
